package main

import "fmt"

func main() {
    // Declare and initialize
    arr1 := [3]int{1, 2, 3}
    arr2 := [...]string{"go", "rust", "zig"}

    fmt.Println("arr1:", arr1)
    fmt.Println("arr2:", arr2)
    fmt.Println("length:", len(arr2))

    // Array is copied, not referenced
    copy := arr1
    copy[0] = 99
    fmt.Println("original:", arr1)
    fmt.Println("copy:", copy)

    // Multi-dimensional
    grid := [2][2]int{{1, 2}, {3, 4}}
    fmt.Println("grid:", grid)
}
